import React, { useState, useEffect, useRef } from 'react';
import InventoryManager from './InventoryManager';

function App() {
  const [menuOpen, setMenuOpen] = useState(false);
  const [currentCategory, setCurrentCategory] = useState('drinks');
  const menuRef = useRef();
  const buttonRef = useRef();

  const handleCategoryChange = (category) => {
    setCurrentCategory(category);
    setMenuOpen(false);
  };

  const handleMenuButton = (e) => {
    e.preventDefault(); // Prevent any default behavior
    if (menuOpen) {
      setMenuOpen(false);
    } else {
      setMenuOpen(true);
    }
  };

  // Handle clicks outside the menu
  useEffect(() => {
    const handleClickOutside = (event) => {
      if (menuOpen && 
          menuRef.current && 
          !menuRef.current.contains(event.target) &&
          !buttonRef.current.contains(event.target)) {
        setMenuOpen(false);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    document.addEventListener('touchstart', handleClickOutside);

    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
      document.removeEventListener('touchstart', handleClickOutside);
    };
  }, [menuOpen]);

  return (
    <div className="app">
      <div className="header">
        <h1>Bar Inventory</h1>
        <button 
          ref={buttonRef}
          className={`menu-button ${menuOpen ? 'open' : ''}`}
          onClick={handleMenuButton}
          onMouseDown={(e) => e.preventDefault()} // Prevent mousedown behavior
          onTouchStart={(e) => e.preventDefault()} // Prevent touch behavior
        >
          <div className="menu-button-icon">
            <span></span>
            <span></span>
            <span></span>
          </div>
        </button>
      </div>

      <div className={`menu-overlay ${menuOpen ? 'open' : ''}`}>
        <div className="menu-card" ref={menuRef}>
          <button 
            className={currentCategory === 'drinks' ? 'active' : ''} 
            onClick={() => handleCategoryChange('drinks')}
          >
            Drinks
          </button>
          <button 
            className={currentCategory === 'tea' ? 'active' : ''} 
            onClick={() => handleCategoryChange('tea')}
          >
            Tea
          </button>
          <button 
            className={currentCategory === 'sirup' ? 'active' : ''} 
            onClick={() => handleCategoryChange('sirup')}
          >
            Monin Sirup
          </button>
        </div>
      </div>

      <InventoryManager category={currentCategory} />
    </div>
  );
}

export default App;
